+        tokio::select! {
+            () = done.cancelled() => return Ok(()),
+            _ = ping_interval.tick() => {
+                socket
+                    .send(WebSocketMessage::Ping(Vec::new().into()))
+                    .await
+                    .map_err(|err| WorkerControlConnectError::Other(anyhow::Error::new(err)))?;
             }
